CustomField.formula:
IF( RecordType.DeveloperName == 'Input_Checkbox', IF(Input_Checkbox__c, "TRUE", "FALSE"), 
IF( RecordType.DeveloperName == 'Input_Currency',
"$" &
IF(Input_Currency__c >= 1000000, TEXT(FLOOR(Input_Currency__c / 1000000)) & ",", "") &
IF(Input_Currency__c >= 1000, RIGHT(TEXT(FLOOR(Input_Currency__c / 1000)), 3) & ",", "") &
RIGHT(TEXT(FLOOR(Input_Currency__c)), 3) & "." &
IF(MOD(Input_Currency__c, 1) * 100 < 10, "0" & TEXT(ROUND(MOD(Input_Currency__c, 1) * 100, 0)), TEXT(ROUND(MOD(Input_Currency__c, 1) * 100, 0))),
IF( RecordType.DeveloperName == 'Input_Date', TEXT( Input_Date__c ),
IF( RecordType.DeveloperName == 'Input_Date_Time', TEXT( Input_Datetime__c ), 
IF( RecordType.DeveloperName == 'Input_Number', TEXT( Input_Number__c ),
IF( RecordType.DeveloperName == 'Input_Text', Input_Text__c,
IF(RecordType.DeveloperName == 'Input_Email', Input_Text__c,
IF( RecordType.DeveloperName == 'Input_Address', Input_Street__c & ", " & Input_City__c & ", " & Input_State_Province__c & "," & Input_Postal_Code__c,
IF( RecordType.DeveloperName == 'Input_Picklist', Input_Text__c,
IF( RecordType.DeveloperName == 'Input_Radio_Group', Input_Text__c,
IF( RecordType.DeveloperName == 'Input_Checkbox_Group', Input_Text__c,
IF( RecordType.DeveloperName == 'Input_File', if(Input_Files_Uploaded__c > 0, TEXT(Input_Files_Uploaded__c), ''),
IF( RecordType.DeveloperName == 'Input_Record_List', if(Input_Record_List__c > 0, TEXT(Input_Record_List__c), ''), ''
 )
 )
 )
 )
 )
 )
 ) 
 )
 )
 )
 )
 )
 )
